'@
$BackedUp = @{}

function Decode-Text([string]$Value) {
    return [System.Text.Encoding]::UTF8.GetString(
        [System.Convert]::FromBase64String($Value)
    )
}

foreach ($Item in $Items) {
    $Path = Join-Path $ProjectRoot $Item.file

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "File not found: $Path"
    }

    $Content = [System.IO.File]::ReadAllText(
        $Path,
        [System.Text.Encoding]::UTF8
    )

    $Content = $Content.Replace("`r`n", "`n")

    $OldText = Decode-Text $Item.old
    $NewText = Decode-Text $Item.new

    if ($Content.Contains($NewText)) {
        Write-Host "Already applied: $($Item.label)"
        continue
    }

    if (-not $Content.Contains($OldText)) {
        throw "Target not found: $($Item.label)"
    }

    if (-not $BackedUp.ContainsKey($Path)) {
        $Stamp = Get-Date -Format "yyyyMMdd-HHmmss"
        Copy-Item -LiteralPath $Path -Destination "$Path.backup-$Stamp" -Force
        $BackedUp[$Path] = $true
    }

    $Updated = $Content.Replace($OldText, $NewText)
    [System.IO.File]::WriteAllText($Path, $Updated, $Utf8NoBom)

    Write-Host "Applied: $($Item.label)"
}

Write-Host ""
Write-Host "DONE: frontend permission patches applied."
